  method: T,
  params?: ProtocolMapping.Commands[T]['paramsType'][0],
  options?: CommandOptions,
): Promise<ProtocolMapping.Commands[T]['returnType']> {
  // There is only ever 1 param arg passed, but the Protocol defines it as an
